import { DOCUMENT } from '@angular/common';
import { Inject, Injectable } from '@angular/core';
import { BehaviorSubject, Observable, Subject } from 'rxjs';

export interface CookieConsentPreferences {
  analytics: boolean;
}

export interface CookieConsentState extends CookieConsentPreferences {
  version: 2;
  decidedAt: string;
}

@Injectable({
  providedIn: 'root'
})
export class CookieConsentService {
  private readonly storageKey = 'site-cookie-consent-v2';
  private readonly legacyStorageKey = 'cookie-consent';
  private readonly cookieName = 'site_cookie_consent';
  private readonly consentVersion = 2;
  private readonly consentMaxAgeSeconds = 60 * 60 * 24 * 180;
  private readonly consentSubject = new BehaviorSubject<CookieConsentState | null>(null);
  private readonly preferencesRequestSubject = new Subject<void>();

  constructor(@Inject(DOCUMENT) private readonly document: Document) {
    this.consentSubject.next(this.readStoredConsent());
  }

  getConsent(): CookieConsentState | null {
    return this.consentSubject.value;
  }

  getConsent$(): Observable<CookieConsentState | null> {
    return this.consentSubject.asObservable();
  }

  getPreferencesRequests$(): Observable<void> {
    return this.preferencesRequestSubject.asObservable();
  }

  hasAnalyticsConsent(): boolean {
    return this.consentSubject.value?.analytics === true;
  }

  requestPreferences(): void {
    this.preferencesRequestSubject.next();
  }

  saveConsent(preferences: CookieConsentPreferences): void {
    const consent: CookieConsentState = {
      version: this.consentVersion,
      analytics: preferences.analytics,
      decidedAt: new Date().toISOString()
    };
    const serializedConsent = JSON.stringify(consent);

    this.getStorage()?.setItem(this.storageKey, serializedConsent);
    this.getStorage()?.removeItem(this.legacyStorageKey);
    this.document.cookie = [
      `${this.cookieName}=${encodeURIComponent(serializedConsent)}`,
      'Path=/',
      `Max-Age=${this.consentMaxAgeSeconds}`,
      'SameSite=Lax',
      this.document.location?.protocol === 'https:' ? 'Secure' : ''
    ].filter(Boolean).join('; ');
    this.consentSubject.next(consent);
  }

  clearConsent(): void {
    this.getStorage()?.removeItem(this.storageKey);
    this.getStorage()?.removeItem(this.legacyStorageKey);
    this.document.cookie = `${this.cookieName}=; Path=/; Max-Age=0; SameSite=Lax`;
    this.consentSubject.next(null);
  }

  private readStoredConsent(): CookieConsentState | null {
    const serializedConsent = this.getStorage()?.getItem(this.storageKey) || this.readConsentCookie();

    if (!serializedConsent) {
      return null;
    }

    try {
      const consent = JSON.parse(serializedConsent) as Partial<CookieConsentState>;
      if (
        consent.version !== this.consentVersion
        || typeof consent.analytics !== 'boolean'
        || !consent.decidedAt
        || this.isExpired(consent.decidedAt)
      ) {
        this.clearInvalidStoredConsent();
        return null;
      }

      return consent as CookieConsentState;
    } catch {
      this.clearInvalidStoredConsent();
      return null;
    }
  }

  private readConsentCookie(): string | null {
    const prefix = `${this.cookieName}=`;
    const cookie = this.document.cookie
      .split(';')
      .map((entry) => entry.trim())
      .find((entry) => entry.startsWith(prefix));

    return cookie ? decodeURIComponent(cookie.slice(prefix.length)) : null;
  }

  private isExpired(decidedAt: string): boolean {
    const decidedAtTimestamp = Date.parse(decidedAt);
    if (!Number.isFinite(decidedAtTimestamp)) {
      return true;
    }

    return Date.now() - decidedAtTimestamp >= this.consentMaxAgeSeconds * 1000;
  }

  private clearInvalidStoredConsent(): void {
    this.getStorage()?.removeItem(this.storageKey);
    this.getStorage()?.removeItem(this.legacyStorageKey);
    this.document.cookie = `${this.cookieName}=; Path=/; Max-Age=0; SameSite=Lax`;
  }

  private getStorage(): Storage | null {
    try {
      return this.document.defaultView?.localStorage ?? null;
    } catch {
      return null;
    }
  }
}
